const e=JSON.parse('{"key":"v-019d8837","path":"/learningNote/Computer_Network/%E4%BB%80%E4%B9%88%E6%98%AFSMTP.html","title":"什么是SMTP","lang":"zh-CN","frontmatter":{"title":"什么是SMTP","category":["Computer","Network","basic"]},"headers":[{"level":2,"title":"介绍","slug":"介绍","link":"#介绍","children":[]},{"level":2,"title":"基本操作","slug":"基本操作","link":"#基本操作","children":[]},{"level":2,"title":"参考书","slug":"参考书","link":"#参考书","children":[]}],"git":{"createdTime":1699177945000,"updatedTime":1699177945000,"contributors":[{"name":"Jeacson_Snake","email":"Jeacson_Snake@outlook.com","commits":1}]},"readingTime":{"minutes":5.41,"words":1624},"filePathRelative":"learningNote/Computer_Network/什么是SMTP.md","localizedDate":"2023年11月5日","excerpt":"<h2> 介绍</h2>\\n<p><strong>SMTP(Simple Mail Transfer Protocol, 简单邮件传输协议)</strong> 是一种提供可靠且有效的电子邮件传输的协议，主要用于系统之间的邮件信息传递，并提供有关来信的通知。</p>\\n<h2> 基本操作</h2>\\n<p>为了说明 SMTP 的基本操作，让我们来假设一个常见的场景。假设 Alice 想要给 Bob 发送一条简单的 ASCII 消息：</p>\\n<ol>\\n<li>Alice 调用其电子邮件用户代理，编写邮件，在提供 Bob 的电子邮件地址 (例如<a href=\\"mailto:bob@someschool.edu\\">bob@someschool.edu</a>) 后指示该用户代理发送邮件;</li>\\n<li>Alice 的用户代理将信息发送到她的邮件服务器，该信息会被放入邮件服务器的信息队列中;</li>\\n<li>在 Alice 的邮件服务器上运行的 SMTP 客户端会发现被提交到该信息队列中的信息。于是这个 SMTP 客户端在找到收件人 Bob 的邮件地址后，尝试与运行在收件人 Bob 邮件服务器上的 SMTP 服务器建立 TCP 连接;</li>\\n<li>经过一些初始 SMTP 握手后，SMTP 客户端通过 TCP 连接将 Alice 的邮件发送到 Bob 的邮件服务器上;</li>\\n<li>Bob 的 SMTP 服务器端接收到该信息后，邮件服务器会将信息放入 Bob 的邮箱;</li>\\n<li>最后当 Bob 调用他的用户代理时，他便可以在任意时间阅读邮件了。</li>\\n</ol>"}');export{e as data};
